VALUES
  ('diplomatic-823d6974-moex-00496', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '關於列強從清末至民國初年在山東的活動，下列敘述何者錯誤？', '["光緒23年（1897年）德國出兵占據膠州灣，開啟了接下來的「瓜分危機」", "民國3年（1914年），第一次世界大戰爆發，日本藉口「英日同盟」而對德宣戰，並因此取得 山東青島的控制權", "民國4年（1915年）中日「二十一條」談判，袁世凱承認日本繼承德國在山東的一切權利，換 文中表示對於日本提議「欣然同意」，成為後來巴黎和會上，日本取得山東的憑據", "民國8年（1919年）5月4日，巴黎和會有關山東問題的決議，傳回國內，北京學生遊行抗議， 要求當局不得簽約，懲處相關官員，成為「五四運動」的導火線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:37+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00497', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '中日關係於民國20年（1931年）「九一八」事變後不斷惡化，下列敘述何者錯誤？', '["民國21年（1932年），日本激進軍人闖入東京首相官邸，槍殺了傾向和平解決中日問題的首相 田中義一，史稱「五一五」事件", "民國22年（1933年），日軍進攻熱河，與中國軍隊爆發「長城戰役」，最後以中日《塘沽協定》 作結", "民國24年（1935年），日本製造「華北自治運動」，提出「廣田三原則」的外相是廣田弘毅", "民國26年（1937年），日軍進攻北平附近蘆溝橋，史稱「七七事變」，衝突旋即擴大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:37+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00498', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '誰創造了「軟實力」這個用語？', '["奈伊（JosephNye）", "米爾斯海默（JohnMearsheimer）", "季辛吉（HenryKissinger）", "溫特（AlexanderWendt）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:37+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00499', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '下列那個不是第一次世界大戰的起因？', '["列強之間秘密聯盟失控以致不可收拾", "英俄法敵對關係已然改善", "同盟國與軸心國爭奪勢力範圍日益激烈", "德國施行大海軍計畫挑戰英國海權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:37+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00500', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '關於清末民初的外蒙和西藏問題，下列敘述何者錯誤？', '["駐印度的英軍曾經兩次侵入西藏", "民國3年（1914年），中、英、藏三方在印度簽署了《西姆拉條約》（SimlaAccord），並得到袁 世凱政府的正式承認", "辛亥革命爆發，外蒙進行第一次的獨立運動", "民國6年（1917年）俄國「十月革命」爆發，其後赤軍、白軍內戰曾波及外蒙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:37+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00501', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '依司法院大法官之解釋，有關新聞自由之敘述，下列何者正確？', '["唯有報導政治事務之內容，才受新聞自由之憲法保障", "受新聞自由保障之客體，不包括娛樂與運動新聞", "受新聞自由保障之客體，僅限於報導最終呈現之內容", "受新聞自由保障之主體，包括從事新聞工作之個人與事業在內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:38+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00502', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '依憲法增修條文規定，關於立法委員之不受逮捕特權，下列敘述何者錯誤？', '["僅限於會期中，始得主張此項特權", "僅限於立法院內之行為，始得主張此項特權", "若為現行犯，則不得主張此項特權", "經立法院許可，仍得逮捕立法委員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:38+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00503', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '依憲法及增修條文規定，下列有關正、副總統缺位之敘述，何者錯誤？', '["總統缺位時，由副總統繼任至原任期屆滿為止", "副總統缺位時，總統應經行政院會議之議決，提名候選人", "行政院院長代行總統職權，其期限不得逾3個月", "正、副總統皆缺位時，由自由地區全體人民直選，補選出繼任者，繼任至原任期屆滿為止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:38+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00504', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '下列何者不屬於國家賠償責任範圍？', '["警察駕駛警車巡邏時撞傷人民", "人民駕車掉入高速公路路面坑洞而受傷", "人民所有之既成道路因提供公眾通行而無法自由使用", "人民因為公務員怠於執行職務而死亡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:38+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00505', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-111-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '有關憲法之施行及效力，下列敘述何者正確？', '["憲法增修條文，應先經大法官審查確定無違憲後，方得公布施行", "憲法增修條文，係由總統令公布實施", "法律與憲法是否牴觸，應由總統召集院際調解委員會確認決定", "命令與憲法是否牴觸，應由代表民意的立法機關確認決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:38+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL)
